     1→// Phase 5: 타입 시스템 기본 정의
     2→
     3→/**
     4→ * Primitive 타입
     5→ */
     6→export enum PrimitiveType {
     7→  NUM = "num",
     8→  STR = "str",
     9→  BOOL = "bool",
    10→  NULL = "null",
    11→  UNKNOWN = "unknown",
    12→}
    13→
    14→/**
    15→ * 타입 종류
    16→ */
    17→export type Type =
    18→  | { kind: "primitive"; type: PrimitiveType }
    19→  | { kind: "array"; elementType: Type }
    20→  | { kind: "object"; properties: Map<string, Type> }
    21→  | { kind: "fn"; paramTypes: Type[]; returnType: Type }
    22→  | { kind: "union"; types: Type[] }
    23→  | { kind: "never" };
    24→
    25→/**
    26→ * 타입 검사 오류
    27→ */
    28→export interface TypeCheckError {
    29→  message: string
    30→  line?: number
    31→  column?: number
    32→  variable?: string
    33→  expected?: Type
    34→  actual?: Type
    35→}
    36→
    37→/**
    38→ * 타입 검사 결과
    39→ */
    40→export interface TypeCheckResult {
    41→  success: boolean
    42→  errors: TypeCheckError[]
    43→  types?: Map<string, Type>
    44→}
    45→
    46→/**
    47→ * 제약 조건
    48→ */
    49→export interface Constraint {
    50→  variable: string
    51→  expectedType: Type
    52→  actualType?: Type
    53→  location?: { line: number; column: number }
    54→}
    55→
    56→/**
    57→ * 충돌 보고서
    58→ */
    59→export interface ConflictReport {
    60→  variable: string
    61→  type1: Type
    62→  type2: Type
    63→  message: string
    64→}
    65→
    66→/**
    67→ * 타입 호환성 확인
    68→ */
    69→export function typesCompatible(type1: Type, type2: Type): boolean {
    70→  // Same type
    71→  if (JSON.stringify(type1) === JSON.stringify(type2)) {
    72→    return true
    73→  }
    74→
    75→  // Primitive types
    76→  if (type1.kind === "primitive" && type2.kind === "primitive") {
    77→    return type1.type === type2.type
    78→  }
    79→
    80→  // Array types
    81→  if (type1.kind === "array" && type2.kind === "array") {
    82→    return typesCompatible(type1.elementType, type2.elementType)
    83→  }
    84→
    85→  // Union types - check if type2 is in union
    86→  if (type2.kind === "union") {
    87→    return type2.types.some((t) => typesCompatible(type1, t))
    88→  }
    89→
    90→  // Unknown type accepts anything
    91→  if (type1.kind === "primitive" && type1.type === PrimitiveType.UNKNOWN) {
    92→    return true
    93→  }
    94→  if (type2.kind === "primitive" && type2.type === PrimitiveType.UNKNOWN) {
    95→    return true
    96→  }
    97→
    98→  return false
    99→}
   100→
   101→/**
   102→ * 타입 문자열 표현
   103→ */
   104→export function typeToString(type: Type): string {
   105→  switch (type.kind) {
   106→    case "primitive":
   107→      return type.type
   108→
   109→    case "array":
   110→      return `array[${typeToString(type.elementType)}]`
   111→
   112→    case "object":
   113→      const props = Array.from(type.properties.entries())
   114→        .map(([k, v]) => `${k}: ${typeToString(v)}`)
   115→        .join(", ")
   116→      return `object{${props}}`
   117→
   118→    case "fn":
   119→      const params = type.paramTypes.map(typeToString).join(", ")
   120→      return `(${params}) -> ${typeToString(type.returnType)}`
   121→
   122→    case "union":
   123→      return type.types.map(typeToString).join(" | ")
   124→
   125→    case "never":
   126→      return "never"
   127→  }
   128→}
   129→
   130→/**
   131→ * 타입 파싱 (문자열 → Type)
   132→ */
   133→export function parseType(typeStr: string): Type {
   134→  typeStr = typeStr.trim()
   135→
   136→  // Primitive types
   137→  if (typeStr === "num") {
   138→    return { kind: "primitive", type: PrimitiveType.NUM }
   139→  }
   140→  if (typeStr === "str") {
   141→    return { kind: "primitive", type: PrimitiveType.STR }
   142→  }
   143→  if (typeStr === "bool") {
   144→    return { kind: "primitive", type: PrimitiveType.BOOL }
   145→  }
   146→  if (typeStr === "null") {
   147→    return { kind: "primitive", type: PrimitiveType.NULL }
   148→  }
   149→
   150→  // Array types
   151→  if (typeStr.startsWith("array[") && typeStr.endsWith("]")) {
   152→    const elementTypeStr = typeStr.substring(6, typeStr.length - 1)
   153→    return {
   154→      kind: "array",
   155→      elementType: parseType(elementTypeStr),
   156→    }
   157→  }
   158→
   159→  // Union types
   160→  if (typeStr.includes(" | ")) {
   161→    const types = typeStr.split(" | ").map((t) => parseType(t.trim()))
   162→    return { kind: "union", types }
   163→  }
   164→
   165→  // Default to unknown
   166→  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   167→}
   168→
   169→/**
   170→ * 연산 결과 타입 결정
   171→ */
   172→export function getOperationResultType(
   173→  op: string,
   174→  leftType: Type,
   175→  rightType: Type
   176→): Type {
   177→  // Primitive operations
   178→  if (
   179→    leftType.kind === "primitive" &&
   180→    rightType.kind === "primitive"
   181→  ) {
   182→    const left = leftType.type
   183→    const right = rightType.type
   184→
   185→    // Numeric operations
   186→    if (op === "Add") {
   187→      if (left === PrimitiveType.NUM && right === PrimitiveType.NUM) {
   188→        return { kind: "primitive", type: PrimitiveType.NUM }
   189→      }
   190→      // String concatenation
   191→      if (left === PrimitiveType.STR || right === PrimitiveType.STR) {
   192→        return { kind: "primitive", type: PrimitiveType.STR }
   193→      }
   194→    }
   195→
   196→    if (
   197→      (op === "Sub" || op === "Mul" || op === "Div" || op === "Mod") &&
   198→      left === PrimitiveType.NUM &&
   199→      right === PrimitiveType.NUM
   200→    ) {
   201→      return { kind: "primitive", type: PrimitiveType.NUM }
   202→    }
   203→
   204→    // Comparison operations
   205→    if (
   206→      op === "Eq" ||
   207→      op === "Neq" ||
   208→      op === "Lt" ||
   209→      op === "Gt" ||
   210→      op === "Lte" ||
   211→      op === "Gte"
   212→    ) {
   213→      return { kind: "primitive", type: PrimitiveType.BOOL }
   214→    }
   215→
   216→    // Logical operations
   217→    if (
   218→      (op === "And" || op === "Or") &&
   219→      left === PrimitiveType.BOOL &&
   220→      right === PrimitiveType.BOOL
   221→    ) {
   222→      return { kind: "primitive", type: PrimitiveType.BOOL }
   223→    }
   224→  }
   225→
   226→  // Array operations
   227→  if (op === "Add" && leftType.kind === "array" && rightType.kind === "array") {
   228→    // Array concatenation results in array
   229→    return leftType
   230→  }
   231→
   232→  return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   233→}
   234→
   235→/**
   236→ * 타입 좁혀짐 (Type Narrowing)
   237→ */
   238→export function narrowType(type: Type, condition: Type): Type {
   239→  // Union 타입에서 일부만 선택
   240→  if (type.kind === "union") {
   241→    for (const t of type.types) {
   242→      if (typesCompatible(t, condition)) {
   243→        return t
   244→      }
   245→    }
   246→  }
   247→
   248→  return type
   249→}
   250→
   251→/**
   252→ * 타입 확대 (Type Widening)
   253→ */
   254→export function widenType(...types: Type[]): Type {
   255→  if (types.length === 0) {
   256→    return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   257→  }
   258→
   259→  if (types.length === 1) {
   260→    return types[0]
   261→  }
   262→
   263→  // 여러 타입을 Union으로 결합
   264→  const uniqueTypes = types.filter(
   265→    (t, i, arr) =>
   266→      arr.findIndex((u) => JSON.stringify(u) === JSON.stringify(t)) === i
   267→  )
   268→
   269→  if (uniqueTypes.length === 1) {
   270→    return uniqueTypes[0]
   271→  }
   272→
   273→  return { kind: "union", types: uniqueTypes }
   274→}
   275→
   276→/**
   277→ * 타입 추론 기본 규칙
   278→ */
   279→export function inferTypeFromValue(value: any): Type {
   280→  if (value === null || value === undefined) {
   281→    return { kind: "primitive", type: PrimitiveType.NULL }
   282→  }
   283→
   284→  switch (typeof value) {
   285→    case "number":
   286→      return { kind: "primitive", type: PrimitiveType.NUM }
   287→    case "string":
   288→      return { kind: "primitive", type: PrimitiveType.STR }
   289→    case "boolean":
   290→      return { kind: "primitive", type: PrimitiveType.BOOL }
   291→    default:
   292→      return { kind: "primitive", type: PrimitiveType.UNKNOWN }
   293→  }
   294→}
   295→
   296→/**
   297→ * 함수 타입 생성
   298→ */
   299→export function createFunctionType(
   300→  paramTypes: Type[],
   301→  returnType: Type
   302→): Type {
   303→  return {
   304→    kind: "fn",
   305→    paramTypes,
   306→    returnType,
   307→  }
   308→}
   309→
   310→/**
   311→ * 객체 타입 생성
   312→ */
   313→export function createObjectType(
   314→  properties: Map<string, Type>
   315→): Type {
   316→  return {
   317→    kind: "object",
   318→    properties,
   319→  }
   320→}
   321→
   322→/**
   323→ * 배열 타입 생성
   324→ */
   325→export function createArrayType(elementType: Type): Type {
   326→  return {
   327→    kind: "array",
   328→    elementType,
   329→  }
   330→}
   331→
   332→/**
   333→ * 기본 타입 미리 정의
   334→ */
   335→export const BUILTIN_TYPES = {
   336→  NUM: { kind: "primitive" as const, type: PrimitiveType.NUM },
   337→  STR: { kind: "primitive" as const, type: PrimitiveType.STR },
   338→  BOOL: { kind: "primitive" as const, type: PrimitiveType.BOOL },
   339→  NULL: { kind: "primitive" as const, type: PrimitiveType.NULL },
   340→  UNKNOWN: { kind: "primitive" as const, type: PrimitiveType.UNKNOWN },
   341→  NEVER: { kind: "never" as const },
   342→}
