     1→// Phase 5: TypeChecker - 정적 타입 검증
     2→
     3→import { Expr, Stmt, Program } from "./ast"
     4→import {
     5→  Type,
     6→  PrimitiveType,
     7→  TypeCheckError,
     8→  TypeCheckResult,
     9→  typesCompatible,
    10→  typeToString,
    11→  getOperationResultType,
    12→  inferTypeFromValue,
    13→  BUILTIN_TYPES,
    14→} from "./type-system"
    15→
    16→/**
    17→ * TypeChecker: AST 기반 정적 타입 검증
    18→ */
    19→export class TypeChecker {
    20→  private env: Map<string, Type> = new Map()
    21→  private functionTypes: Map<string, Type> = new Map()
    22→  private errors: TypeCheckError[] = []
    23→
    24→  /**
    25→   * 전체 프로그램 타입 검사
    26→   */
    27→  public check(program: Program): TypeCheckResult {
    28→    this.errors = []
    29→    this.env.clear()
    30→    this.functionTypes.clear()
    31→
    32→    // First pass: 함수 정의 수집
    33→    for (const stmt of program.stmts) {
    34→      if (stmt.kind === "fn") {
    35→        this.registerFunctionType(stmt)
    36→      }
    37→    }
    38→
    39→    // Second pass: 함수 본문 및 다른 명령문 검사
    40→    for (const stmt of program.stmts) {
    41→      this.checkStmt(stmt)
    42→    }
    43→
    44→    return {
    45→      success: this.errors.length === 0,
    46→      errors: this.errors,
    47→      types: new Map(this.env),
    48→    }
    49→  }
    50→
    51→  /**
    52→   * 함수 타입 등록
    53→   */
    54→  private registerFunctionType(stmt: Stmt): void {
    55→    if (stmt.kind === "fn") {
    56→      const fnStmt = stmt as any
    57→      const paramTypes: Type[] = (fnStmt.params || []).map(() => ({
    58→        kind: "primitive" as const,
    59→        type: PrimitiveType.UNKNOWN,
    60→      }))
    61→
    62→      const returnType: Type = {
    63→        kind: "primitive",
    64→        type: PrimitiveType.UNKNOWN,
    65→      }
    66→
    67→      const fnType: Type = {
    68→        kind: "fn",
    69→        paramTypes,
    70→        returnType,
    71→      }
    72→
    73→      this.functionTypes.set(fnStmt.name, fnType)
    74→    }
    75→  }
    76→
    77→  /**
    78→   * 명령문 타입 검사
    79→   */
    80→  private checkStmt(stmt: Stmt): void {
    81→    switch (stmt.kind) {
    82→      case "print": {
    83→        const printStmt = stmt as any
    84→        this.checkExpr(printStmt.expr)
    85→        break
    86→      }
    87→
    88→      case "expr": {
    89→        const exprStmt = stmt as any
    90→        this.checkExpr(exprStmt.expr)
    91→        break
    92→      }
    93→
    94→      case "let": {
    95→        const letStmt = stmt as any
    96→        if (letStmt.init) {
    97→          const valueType = this.checkExpr(letStmt.init)
    98→          this.env.set(letStmt.name, valueType)
    99→        } else {
   100→          this.env.set(letStmt.name, BUILTIN_TYPES.UNKNOWN)
   101→        }
   102→        break
   103→      }
   104→
   105→      case "fn": {
   106→        const fnStmt = stmt as any
   107→        const savedEnv = new Map(this.env)
   108→
   109→        // 파라미터를 환경에 추가
   110→        for (const param of fnStmt.params || []) {
   111→          this.env.set(param, {
   112→            kind: "primitive",
   113→            type: PrimitiveType.UNKNOWN,
   114→          })
   115→        }
   116→
   117→        // 함수 본문 검사
   118→        for (const s of fnStmt.body || []) {
   119→          this.checkStmt(s)
   120→        }
   121→
   122→        this.env = savedEnv
   123→        break
   124→      }
   125→
   126→      case "if": {
   127→        const ifStmt = stmt as any
   128→        this.checkExpr(ifStmt.cond)
   129→        for (const s of ifStmt.then || []) {
   130→          this.checkStmt(s)
   131→        }
   132→        if (ifStmt.else) {
   133→          for (const s of ifStmt.else) {
   134→            this.checkStmt(s)
   135→          }
   136→        }
   137→        break
   138→      }
   139→
   140→      case "for": {
   141→        const forStmt = stmt as any
   142→        this.checkExpr(forStmt.iter)
   143→        // 루프 변수를 환경에 추가
   144→        this.env.set(forStmt.name, BUILTIN_TYPES.UNKNOWN)
   145→        for (const s of forStmt.body || []) {
   146→          this.checkStmt(s)
   147→        }
   148→        break
   149→      }
   150→
   151→      case "while": {
   152→        const whileStmt = stmt as any
   153→        this.checkExpr(whileStmt.cond)
   154→        for (const s of whileStmt.body || []) {
   155→          this.checkStmt(s)
   156→        }
   157→        break
   158→      }
   159→
   160→      case "return": {
   161→        const returnStmt = stmt as any
   162→        if (returnStmt.value) {
   163→          this.checkExpr(returnStmt.value)
   164→        }
   165→        break
   166→      }
   167→
   168→      case "block": {
   169→        const blockStmt = stmt as any
   170→        for (const s of blockStmt.body || []) {
   171→          this.checkStmt(s)
   172→        }
   173→        break
   174→      }
   175→
   176→      case "try": {
   177→        const tryStmt = stmt as any
   178→        for (const s of tryStmt.body || []) {
   179→          this.checkStmt(s)
   180→        }
   181→        if (tryStmt.catchVar) {
   182→          this.env.set(tryStmt.catchVar, BUILTIN_TYPES.UNKNOWN)
   183→        }
   184→        for (const s of tryStmt.catchBody || []) {
   185→          this.checkStmt(s)
   186→        }
   187→        for (const s of tryStmt.finallyBody || []) {
   188→          this.checkStmt(s)
   189→        }
   190→        break
   191→      }
   192→
   193→      case "throw": {
   194→        const throwStmt = stmt as any
   195→        this.checkExpr(throwStmt.expr)
   196→        break
   197→      }
   198→
   199→      case "if-let": {
   200→        const ifLetStmt = stmt as any
   201→        this.checkExpr(ifLetStmt.value)
   202→        // 패턴 바인딩
   203→        if (ifLetStmt.pattern.kind === "ident") {
   204→          this.env.set(ifLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   205→        }
   206→        for (const s of ifLetStmt.body || []) {
   207→          this.checkStmt(s)
   208→        }
   209→        if (ifLetStmt.else) {
   210→          for (const s of ifLetStmt.else) {
   211→            this.checkStmt(s)
   212→          }
   213→        }
   214→        break
   215→      }
   216→
   217→      case "while-let": {
   218→        const whileLetStmt = stmt as any
   219→        this.checkExpr(whileLetStmt.value)
   220→        if (whileLetStmt.pattern.kind === "ident") {
   221→          this.env.set(whileLetStmt.pattern.name, BUILTIN_TYPES.UNKNOWN)
   222→        }
   223→        for (const s of whileLetStmt.body || []) {
   224→          this.checkStmt(s)
   225→        }
   226→        break
   227→      }
   228→
   229→      case "match": {
   230→        const matchStmt = stmt as any
   231→        this.checkExpr(matchStmt.subject)
   232→        for (const arm of matchStmt.arms || []) {
   233→          if (arm.pattern) {
   234→            this.checkExpr(arm.pattern)
   235→          }
   236→          if (arm.guard) {
   237→            this.checkExpr(arm.guard)
   238→          }
   239→          for (const s of arm.body || []) {
   240→            this.checkStmt(s)
   241→          }
   242→        }
   243→        break
   244→      }
   245→    }
   246→  }
   247→
   248→  /**
   249→   * 표현식 타입 검사
   250→   */
   251→  public checkExpr(expr: Expr): Type {
   252→    switch (expr.kind) {
   253→      case "number":
   254→        return { kind: "primitive", type: PrimitiveType.NUM }
   255→
   256→      case "string":
   257→        return { kind: "primitive", type: PrimitiveType.STR }
   258→
   259→      case "bool":
   260→        return { kind: "primitive", type: PrimitiveType.BOOL }
   261→
   262→      case "null":
   263→        return { kind: "primitive", type: PrimitiveType.NULL }
   264→
   265→      case "ident": {
   266→        const identExpr = expr as any
   267→        const type = this.env.get(identExpr.name)
   268→        if (!type) {
   269→          this.addError(
   270→            `Undefined variable '${identExpr.name}'`,
   271→            undefined,
   272→            undefined
   273→          )
   274→          return BUILTIN_TYPES.UNKNOWN
   275→        }
   276→        return type
   277→      }
   278→
   279→      case "assign": {
   280→        const assignExpr = expr as any
   281→        const valueType = this.checkExpr(assignExpr.value)
   282→
   283→        // target이 ident인 경우 할당
   284→        if (assignExpr.target.kind === "ident") {
   285→          this.env.set(assignExpr.target.name, valueType)
   286→        }
   287→        return valueType
   288→      }
   289→
   290→      case "binary": {
   291→        const binExpr = expr as any
   292→        const leftType = this.checkExpr(binExpr.left)
   293→        const rightType = this.checkExpr(binExpr.right)
   294→
   295→        // 타입 호환성 검사
   296→        const resultType = getOperationResultType(
   297→          binExpr.op,
   298→          leftType,
   299→          rightType
   300→        )
   301→
   302→        // Add 연산 검증
   303→        if (binExpr.op === "+" || binExpr.op === "Add") {
   304→          if (leftType.kind === "primitive" && rightType.kind === "primitive") {
   305→            const left = leftType.type
   306→            const right = rightType.type
   307→
   308→            if (
   309→              !(
   310→                (left === PrimitiveType.NUM && right === PrimitiveType.NUM) ||
   311→                (left === PrimitiveType.STR || right === PrimitiveType.STR) ||
   312→                (left === PrimitiveType.UNKNOWN ||
   313→                  right === PrimitiveType.UNKNOWN)
   314→              )
   315→            ) {
   316→              this.addError(
   317→                `Cannot add ${typeToString(leftType)} and ${typeToString(rightType)}`,
   318→                undefined,
   319→                undefined,
   320→                undefined,
   321→                leftType,
   322→                rightType
   323→              )
   324→            }
   325→          }
   326→        }
   327→
   328→        return resultType
   329→      }
   330→
   331→      case "unary": {
   332→        const unaryExpr = expr as any
   333→        const operandType = this.checkExpr(unaryExpr.expr)
   334→
   335→        if (unaryExpr.op === "!") {
   336→          if (
   337→            operandType.kind !== "primitive" ||
   338→            operandType.type !== PrimitiveType.BOOL
   339→          ) {
   340→            this.addError(
   341→              `Cannot apply ! to ${typeToString(operandType)}`,
   342→              undefined,
   343→              undefined
   344→            )
   345→          }
   346→          return BUILTIN_TYPES.BOOL
   347→        }
   348→
   349→        if (unaryExpr.op === "-") {
   350→          if (
   351→            operandType.kind !== "primitive" ||
   352→            operandType.type !== PrimitiveType.NUM
   353→          ) {
   354→            this.addError(
   355→              `Cannot negate ${typeToString(operandType)}`,
   356→              undefined,
   357→              undefined
   358→            )
   359→          }
   360→          return BUILTIN_TYPES.NUM
   361→        }
   362→
   363→        return operandType
   364→      }
   365→
   366→      case "call": {
   367→        const callExpr = expr as any
   368→
   369→        // callee에서 함수 이름 추출
   370→        let fnName = ""
   371→        if (callExpr.callee.kind === "ident") {
   372→          fnName = callExpr.callee.name
   373→        }
   374→
   375→        const fnType = this.functionTypes.get(fnName)
   376→
   377→        if (!fnType) {
   378→          this.addError(
   379→            `Undefined function '${fnName}'`,
   380→            undefined,
   381→            undefined
   382→          )
   383→          return BUILTIN_TYPES.UNKNOWN
   384→        }
   385→
   386→        if (fnType.kind === "fn") {
   387→          // 인자 개수 확인
   388→          if ((callExpr.args || []).length !== fnType.paramTypes.length) {
   389→            this.addError(
   390→              `Function '${fnName}' expects ${fnType.paramTypes.length} arguments, got ${(callExpr.args || []).length}`,
   391→              undefined,
   392→              undefined
   393→            )
   394→          }
   395→
   396→          // 인자 타입 검사
   397→          for (let i = 0; i < (callExpr.args || []).length; i++) {
   398→            const argType = this.checkExpr(callExpr.args[i])
   399→            const paramType = fnType.paramTypes[i] || BUILTIN_TYPES.UNKNOWN
   400→
   401→            if (!typesCompatible(argType, paramType)) {
   402→              this.addError(
   403→                `Argument ${i} of '${fnName}': expected ${typeToString(paramType)}, got ${typeToString(argType)}`,
   404→                undefined,
   405→                undefined,
   406→                undefined,
   407→                paramType,
   408→                argType
   409→              )
   410→            }
   411→          }
   412→
   413→          return fnType.returnType
   414→        }
   415→
   416→        return BUILTIN_TYPES.UNKNOWN
   417→      }
   418→
   419→      case "array": {
   420→        const arrayExpr = expr as any
   421→        if ((arrayExpr.elements || []).length === 0) {
   422→          return {
   423→            kind: "array",
   424→            elementType: BUILTIN_TYPES.UNKNOWN,
   425→          }
   426→        }
   427→
   428→        const elementTypes = (arrayExpr.elements || []).map((e: any) =>
   429→          this.checkExpr(e)
   430→        )
   431→
   432→        // 모든 요소 타입이 같은지 확인
   433→        const firstType = elementTypes[0]
   434→        for (let i = 1; i < elementTypes.length; i++) {
   435→          if (!typesCompatible(elementTypes[i], firstType)) {
   436→            this.addError(
   437→              `Array elements have inconsistent types: ${typeToString(firstType)} and ${typeToString(elementTypes[i])}`,
   438→              undefined,
   439→              undefined
   440→            )
   441→          }
   442→        }
   443→
   444→        return {
   445→          kind: "array",
   446→          elementType: firstType,
   447→        }
   448→      }
   449→
   450→      case "index": {
   451→        const indexExpr = expr as any
   452→        const objectType = this.checkExpr(indexExpr.object)
   453→        this.checkExpr(indexExpr.index)
   454→
   455→        if (objectType.kind === "array") {
   456→          return objectType.elementType
   457→        }
   458→        return BUILTIN_TYPES.UNKNOWN
   459→      }
   460→
   461→      case "member": {
   462→        const memberExpr = expr as any
   463→        const objectType = this.checkExpr(memberExpr.object)
   464→
   465→        if (objectType.kind === "object") {
   466→          const propType = objectType.properties.get(memberExpr.property)
   467→          return propType || BUILTIN_TYPES.UNKNOWN
   468→        }
   469→        return BUILTIN_TYPES.UNKNOWN
   470→      }
   471→
   472→      case "object": {
   473→        const objExpr = expr as any
   474→        const properties = new Map<string, Type>()
   475→
   476→        for (const entry of objExpr.entries || []) {
   477→          properties.set(entry.key, this.checkExpr(entry.value))
   478→        }
   479→
   480→        return {
   481→          kind: "object",
   482→          properties,
   483→        }
   484→      }
   485→
   486→      case "fn": {
   487→        const fnExpr = expr as any
   488→        const savedEnv = new Map(this.env)
   489→
   490→        // 파라미터를 환경에 추가
   491→        for (const param of fnExpr.params || []) {
   492→          this.env.set(param, {
   493→            kind: "primitive",
   494→            type: PrimitiveType.UNKNOWN,
   495→          })
   496→        }
   497→
   498→        // 함수 본문 검사
   499→        for (const stmt of fnExpr.body || []) {
   500→          this.checkStmt(stmt)
   501→        }
   502→
   503→        this.env = savedEnv
   504→
   505→        // 함수 타입 반환
   506→        const paramTypes: Type[] = (fnExpr.params || []).map(() => ({
   507→          kind: "primitive" as const,
   508→          type: PrimitiveType.UNKNOWN,
   509→        }))
   510→
   511→        return {
   512→          kind: "fn",
   513→          paramTypes,
   514→          returnType: BUILTIN_TYPES.UNKNOWN,
   515→        }
   516→      }
   517→
   518→      case "ternary": {
   519→        const ternaryExpr = expr as any
   520→        this.checkExpr(ternaryExpr.cond)
   521→        const thenType = this.checkExpr(ternaryExpr.then)
   522→        const elseType = this.checkExpr(ternaryExpr.else)
   523→
   524→        // then과 else 타입이 호환 가능해야 함
   525→        if (!typesCompatible(thenType, elseType)) {
   526→          this.addError(
   527→            `Ternary branch types incompatible: ${typeToString(thenType)} vs ${typeToString(elseType)}`,
   528→            undefined,
   529→            undefined
   530→          )
   531→        }
   532→
   533→        return thenType
   534→      }
   535→
   536→      case "if": {
   537→        const ifExpr = expr as any
   538→        this.checkExpr(ifExpr.cond)
   539→        for (const s of ifExpr.then || []) {
   540→          this.checkStmt(s)
   541→        }
   542→        for (const s of ifExpr.else || []) {
   543→          this.checkStmt(s)
   544→        }
   545→        return BUILTIN_TYPES.UNKNOWN
   546→      }
   547→
   548→      case "match": {
   549→        const matchExpr = expr as any
   550→        this.checkExpr(matchExpr.subject)
   551→        for (const arm of matchExpr.arms || []) {
   552→          if (arm.pattern) {
   553→            this.checkExpr(arm.pattern)
   554→          }
   555→          if (arm.guard) {
   556→            this.checkExpr(arm.guard)
   557→          }
   558→          for (const s of arm.body || []) {
   559→            this.checkStmt(s)
   560→          }
   561→        }
   562→        return BUILTIN_TYPES.UNKNOWN
   563→      }
   564→
   565→      default:
   566→        return BUILTIN_TYPES.UNKNOWN
   567→    }
   568→  }
   569→
   570→  /**
   571→   * 오류 추가
   572→   */
   573→  private addError(
   574→    message: string,
   575→    line?: number,
   576→    column?: number,
   577→    variable?: string,
   578→    expected?: Type,
   579→    actual?: Type
   580→  ): void {
   581→    this.errors.push({
   582→      message,
   583→      line,
   584→      column,
   585→      variable,
   586→      expected,
   587→      actual,
   588→    })
   589→  }
   590→
   591→  /**
   592→   * 환경 조회
   593→   */
   594→  public getEnv(): Map<string, Type> {
   595→    return new Map(this.env)
   596→  }
   597→
   598→  /**
   599→   * 함수 타입 조회
   600→   */
   601→  public getFunctionType(name: string): Type | undefined {
   602→    return this.functionTypes.get(name)
   603→  }
   604→
   605→  /**
   606→   * 오류 개수
   607→   */
   608→  public getErrorCount(): number {
   609→    return this.errors.length
   610→  }
   611→
   612→  /**
   613→   * 오류 목록
   614→   */
   615→  public getErrors(): TypeCheckError[] {
   616→    return [...this.errors]
   617→  }
   618→}
