     1→/**
     2→ * FreeLang v6: Type Inference System
     3→ * 목표: 명시적 타입 선언 없이도 타입을 자동으로 추론
     4→ *
     5→ * 예시:
     6→ *   let x = 10;        // ✅ i32 추론
     7→ *   let y = 3.14;      // ✅ f64 추론
     8→ *   let z = "hello";   // ✅ str 추론
     9→ *   let b = true;      // ✅ bool 추론
    10→ *   let arr = [1,2,3]; // ✅ i32[] 추론
    11→ */
    12→
    13→import { Expr, Stmt } from "./ast";
    14→
    15→export type TypeTag =
    16→  | "i32"      // 32-bit integer
    17→  | "f64"      // 64-bit float
    18→  | "str"      // string
    19→  | "bool"     // boolean
    20→  | "void"     // no return value
    21→  | "any"      // any type (unknown)
    22→  | "array"    // array type
    23→  | "object"   // object type
    24→  | "function" // function type
    25→  | "null";    // null type
    26→
    27→export type TypeInfo = {
    28→  tag: TypeTag;
    29→  elementType?: TypeInfo;  // for arrays
    30→  paramTypes?: TypeInfo[]; // for functions
    31→  returnType?: TypeInfo;   // for functions
    32→};
    33→
    34→// v6.1: Forward Declaration 지원
    35→export interface FunctionSignature {
    36→  name: string;
    37→  paramCount: number;     // 파라미터 수
    38→  returnType: TypeInfo;   // 반환 타입 (pending이면 { tag: "any" })
    39→  isPending: boolean;     // 반환 타입 미확정 (분석 중)
    40→  declaredAt: number;     // 선언 타임스탬프
    41→}
    42→
    43→export class TypeInference {
    44→  private typeTable: Map<string, TypeInfo> = new Map();
    45→  private expressionTypes: Map<any, TypeInfo> = new Map();
    46→  // v6.1: Forward Declaration 지원
    47→  private functionSignatures: Map<string, FunctionSignature> = new Map();
    48→  // v6.1: Call Context Trace - 현재 분석 중인 함수 스택
    49→  private callContextStack: string[] = [];
    50→
    51→  /**
    52→   * 리터럴 값의 타입 추론
    53→   *
    54→   * 예시:
    55→   *   42        → i32
    56→   *   3.14      → f64
    57→   *   "hello"   → str
    58→   *   true/false → bool
    59→   *   [1,2,3]   → i32[]
    60→   */
    61→  inferLiteralType(value: any): TypeInfo {
    62→    if (typeof value === "number") {
    63→      // 정수인지 부동소수점인지 판단
    64→      return Number.isInteger(value)
    65→        ? { tag: "i32" }
    66→        : { tag: "f64" };
    67→    }
    68→
    69→    if (typeof value === "string") {
    70→      return { tag: "str" };
    71→    }
    72→
    73→    if (typeof value === "boolean") {
    74→      return { tag: "bool" };
    75→    }
    76→
    77→    if (Array.isArray(value)) {
    78→      // 배열의 모든 원소가 같은 타입이면 해당 타입 배열
    79→      const elementType = this.inferLiteralType(value[0]);
    80→      const allSame = value.every(v =>
    81→        JSON.stringify(this.inferLiteralType(v)) === JSON.stringify(elementType)
    82→      );
    83→
    84→      if (allSame) {
    85→        return { tag: "array", elementType };
    86→      } else {
    87→        return { tag: "array", elementType: { tag: "any" } };
    88→      }
    89→    }
    90→
    91→    if (value === null) {
    92→      return { tag: "null" };
    93→    }
    94→
    95→    if (typeof value === "object") {
    96→      return { tag: "object" };
    97→    }
    98→
    99→    return { tag: "any" };
   100→  }
   101→
   102→  /**
   103→   * 이진 연산자의 결과 타입 추론
   104→   *
   105→   * 예시:
   106→   *   10 + 20     → i32
   107→   *   3.14 + 2.0  → f64
   108→   *   "a" + "b"   → str
   109→   *   1 < 2       → bool
   110→   */
   111→  inferBinaryOpType(op: string, left: TypeInfo, right: TypeInfo): TypeInfo {
   112→    // 산술 연산
   113→    if (["+", "-", "*", "/", "%"].includes(op)) {
   114→      if (left.tag === "str" || right.tag === "str") {
   115→        return { tag: "str" }; // 문자열 연결
   116→      }
   117→
   118→      if (left.tag === "f64" || right.tag === "f64") {
   119→        return { tag: "f64" }; // 부동소수점
   120→      }
   121→
   122→      return { tag: "i32" }; // 정수
   123→    }
   124→
   125→    // 비교 연산
   126→    if (["<", ">", "<=", ">=", "==", "!="].includes(op)) {
   127→      return { tag: "bool" };
   128→    }
   129→
   130→    // 논리 연산
   131→    if (["&&", "||"].includes(op)) {
   132→      return { tag: "bool" };
   133→    }
   134→
   135→    return { tag: "any" };
   136→  }
   137→
   138→  /**
   139→   * 함수 호출의 반환 타입 추론
   140→   */
   141→  inferFunctionReturnType(funcName: string, argTypes: TypeInfo[]): TypeInfo {
   142→    // 표준 라이브러리 함수들의 반환 타입
   143→    const builtinReturnTypes: Record<string, TypeInfo> = {
   144→      // String functions
   145→      "length": { tag: "i32" },
   146→      "charAt": { tag: "str" },
   147→      "substring": { tag: "str" },
   148→      "toUpperCase": { tag: "str" },
   149→      "toLowerCase": { tag: "str" },
   150→
   151→      // Math functions
   152→      "abs": argTypes[0],      // 입력과 같은 타입
   153→      "sqrt": { tag: "f64" },
   154→      "floor": { tag: "i32" },
   155→      "ceil": { tag: "i32" },
   156→      "round": { tag: "i32" },
   157→
   158→      // Array functions
   159→      "push": { tag: "i32" },   // 배열 길이 반환
   160→      "pop": argTypes[0]?.elementType || { tag: "any" },
   161→      "slice": argTypes[0],     // 배열 반환
   162→
   163→      // Type checking
   164→      "typeof": { tag: "str" },
   165→      "instanceof": { tag: "bool" },
   166→    };
   167→
   168→    return builtinReturnTypes[funcName] || { tag: "any" };
   169→  }
   170→
   171→  /**
   172→   * 변수 선언의 타입 저장
   173→   */
   174→  declareVariable(name: string, type: TypeInfo): void {
   175→    this.typeTable.set(name, type);
   176→  }
   177→
   178→  /**
   179→   * 변수의 타입 조회
   180→   */
   181→  getVariableType(name: string): TypeInfo | undefined {
   182→    return this.typeTable.get(name);
   183→  }
   184→
   185→  /**
   186→   * 타입 호환성 검사
   187→   *
   188→   * 예시:
   189→   *   i32 ← i32 ✅
   190→   *   f64 ← i32 ✅ (타입 캐스트 가능)
   191→   *   str ← i32 ❌ (호환 불가)
   192→   */
   193→  isTypeCompatible(target: TypeInfo, source: TypeInfo): boolean {
   194→    if (target.tag === source.tag) return true;
   195→    if (target.tag === "any" || source.tag === "any") return true;
   196→
   197→    // i32 → f64 호환
   198→    if (target.tag === "f64" && source.tag === "i32") return true;
   199→
   200→    // null → 다른 타입 호환
   201→    if (source.tag === "null") return true;
   202→
   203→    return false;
   204→  }
   205→
   206→  /**
   207→   * 타입 에러 메시지 생성
   208→   */
   209→  generateTypeError(
   210→    line: number,
   211→    column: number,
   212→    expected: TypeInfo,
   213→    actual: TypeInfo,
   214→    context?: string
   215→  ): string {
   216→    return `
   217→Type Error at line ${line}, column ${column}:
   218→  Expected: ${this.typeToString(expected)}
   219→  Actual:   ${this.typeToString(actual)}
   220→  ${context ? `Context: ${context}` : ""}
   221→    `.trim();
   222→  }
   223→
   224→  /**
   225→   * 타입을 문자열로 변환
   226→   */
   227→  private typeToString(type: TypeInfo): string {
   228→    if (type.tag === "array" && type.elementType) {
   229→      return `${this.typeToString(type.elementType)}[]`;
   230→    }
   231→
   232→    if (type.tag === "function" && type.paramTypes && type.returnType) {
   233→      const params = type.paramTypes.map(t => this.typeToString(t)).join(", ");
   234→      return `(${params}) -> ${this.typeToString(type.returnType)}`;
   235→    }
   236→
   237→    return type.tag;
   238→  }
   239→
   240→  /**
   241→   * 타입 추론 결과 리포트
   242→   */
   243→  reportTypeInference(expr: Expr, type: TypeInfo): void {
   244→    // 디버그/로깅용
