### 5. vm-types-test.ts - 기존 테스트 패턴

**테스트 인프라 (재사용 가능)**
```typescript
// 헬퍼 패턴
function parseCode(code: string) {
  const tokens = lex(code)
  return parse(tokens)
}

function checkTypes(code: string) {
  const program = parseCode(code)
  const checker = new TypeChecker()
  return checker.check(program)
